reorderTask(taskId: string, newPosition: number): Task[] | null {
  const task = this.getTask(taskId);
  if (!task) return null;

  const columnTasks = this.getTasksByColumn(task.columnId);
  const oldPosition = task.position;

  if (newPosition < 0 || newPosition >= columnTasks.length) {
    newPosition = Math.max(0, Math.min(newPosition, columnTasks.length - 1));
  }

  if (oldPosition === newPosition) return columnTasks;

  // Shift positions of affected tasks
  for (const t of columnTasks) {
    if (oldPosition < newPosition) {
      // Moving down: shift tasks between old and new up
      if (t.position > oldPosition && t.position <= newPosition) {
        t.position--;
      }
    } else {
      // Moving up: shift tasks between new and old down
      if (t.position >= newPosition && t.position < oldPosition) {
        t.position++;
      }
    }
  }

  task.position = newPosition;
  return this.getTasksByColumn(task.columnId);
}

