describe('reorderTask', () => {
  beforeEach(() => {
    service.addTask(makeTask('a', 'col-1', 0));
    service.addTask(makeTask('b', 'col-1', 1));
    service.addTask(makeTask('c', 'col-1', 2));
    service.addTask(makeTask('d', 'col-1', 3));
  });

  test('moves task down', () => {
    const result = service.reorderTask('a', 2);
    expect(result).not.toBeNull();
    const ids = result!.map(t => t.id);
    expect(ids).toEqual(['b', 'c', 'a', 'd']);
  });

  test('moves task up', () => {
    const result = service.reorderTask('c', 0);
    expect(result).not.toBeNull();
    const ids = result!.map(t => t.id);
    expect(ids).toEqual(['c', 'a', 'b', 'd']);
  });

  test('no-op when same position', () => {
    const result = service.reorderTask('b', 1);
    expect(result).not.toBeNull();
    const ids = result!.map(t => t.id);
    expect(ids).toEqual(['a', 'b', 'c', 'd']);
  });

  test('returns null for unknown task', () => {
    expect(service.reorderTask('unknown', 0)).toBeNull();
  });

  test('clamps out-of-range position', () => {
    const result = service.reorderTask('a', 99);
    expect(result).not.toBeNull();
    expect(result![result!.length - 1].id).toBe('a');
  });
});
